function BrandStrip() {
  const customStyles = `
    .scrollbar-none::-webkit-scrollbar {
      display: none;
    }
    .scrollbar-none {
      -ms-overflow-style: none;
      scrollbar-width: none;
    }
    @keyframes dash {
      to { stroke-dashoffset: -20; }
    }
    .animate-dash-flow {
      stroke-dasharray: 6, 4;
      animation: dash 1.5s linear infinite;
    }
    @keyframes breathe {
      0%, 100% { opacity: 0.15; }
      50% { opacity: 0.45; }
    }
    .animate-breathe {
      animation: breathe 3s ease-in-out infinite;
    }
  `;

  return (
    <div id="brands" className="relative w-full bg-[#06111F] border-y border-white/[0.06] py-5 -mt-12 z-20">
      <style dangerouslySetInnerHTML={{ __html: customStyles }} />
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between overflow-x-auto lg:overflow-visible gap-12 lg:gap-6 scrollbar-none py-1">
          {BRANDS.map((brand) => (
            <div
              key={brand.name}
              className="flex-shrink-0 flex items-center justify-center transition-all duration-300 hover:scale-105"
            >
              {brand.content}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function InteractiveLuxuryMap() {
  const [hoveredNode, setHoveredNode] = useState<MapNode | null>(null);

  return (
    <div
      className="relative h-full w-full overflow-hidden bg-[#06111F] select-none group/map cursor-pointer"
      onClick={() => window.open(MAPS_URL, '_blank')}
    >
      <div className="pointer-events-none absolute inset-0 bg-gradient-to-t from-[#06111F] via-transparent to-[#06111F]/40" />

      <svg className="absolute inset-0 w-full h-full z-10 pointer-events-none">
        {MAP_NODES.map((node) => {
          if (node.isFlagship) return null;
          const isHovered = hoveredNode?.id === node.id;
          return (
            <g key={`link-${node.id}`}>
              <line 
                x1="50%" 
                y1="50%" 
                x2={node.x} 
                y2={node.y} 
                stroke={isHovered ? "#c7a14e" : "rgba(199, 161, 78, 0.25)"} 
                strokeWidth={isHovered ? "2" : "1.2"} 
                opacity={isHovered ? "1" : "0.5"}
                className={isHovered ? "animate-dash-flow" : ""}
                style={{ transition: 'stroke 0.2s, stroke-width 0.2s, opacity 0.2s' }}
              />
            </g>
          );
        })}

        {MAP_NODES.map((node) => {
          if (node.isFlagship) return null;
          const isHovered = hoveredNode?.id === node.id;
          return (
            <g key={`dot-${node.id}`}>
              <circle
                cx={node.x}
                cy={node.y}
                r={isHovered ? 12 : 6}
                fill="none"
                stroke={node.color}
                strokeWidth="1"
                opacity={isHovered ? 0.95 : 0.4}
                className="transition-all duration-300"
              />
              <circle
                cx={node.x}
                cy={node.y}
                r={isHovered ? 5.5 : 3.5}
                fill={node.color}
                opacity={isHovered ? 1 : 0.8}
                className="transition-all duration-300"
              />
            </g>
          );
        })}

        {/* Labels drawn directly on map */}
        {MAP_NODES.map((node) => {
          if (node.isFlagship) return null;
          const isHovered = hoveredNode?.id === node.id;
          return (
            <text
              key={`label-${node.id}`}
              x={node.x}
              y={node.y}
              dx={node.dx || "0"}
              dy={node.dy || "0"}
              textAnchor={node.textAnchor || "start"}
              fill={isHovered ? "#ffffff" : node.color}
              className="text-[9px] sm:text-[10px] font-sans font-bold select-none transition-colors duration-300"
              style={{
                textShadow: '0 1px 3px rgba(0,0,0,0.95), 0 0 2px rgba(0,0,0,0.85)',
                letterSpacing: '0.03em',
                opacity: isHovered ? 1.0 : 0.95
              }}
            >
              {node.name}
            </text>
          );
        })}

        {/* Flagship Store Label */}
        <text
          x="50%"
          y="50%"
          dy="18"
          textAnchor="middle"
          fill="#c7a14e"
          className="text-[9px] sm:text-[10.5px] font-sans font-extrabold select-none"
          style={{
            textShadow: '0 1px 4px rgba(0,0,0,0.95), 0 0 3px rgba(0,0,0,0.85)',
            letterSpacing: '0.05em'
          }}
        >
          Hanumangarh Town
        </text>

        <circle cx="50%" cy="50%" r="30" fill="none" stroke="#c7a14e" strokeWidth="1" className="animate-breathe" />
        <circle cx="50%" cy="50%" r="20" fill="none" stroke="#c7a14e" strokeWidth="1.5" className="animate-breathe" style={{ animationDelay: '1.5s' }} />
      </svg>

      <div
        className="absolute z-20 pointer-events-none"
        style={{ left: '50%', top: '50%', transform: 'translate(-50%, -100%)' }}
      >
        <svg
          width="40"
          height="54"
          viewBox="0 0 40 54"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          style={{ filter: 'drop-shadow(0 4px 16px rgba(199,161,78,0.75))' }}
        >
          <path
            d="M20 0C9.0 0 0 9.0 0 20C0 31 20 54 20 54C20 54 40 31 40 20C40 9.0 31 0 20 0Z"
            fill="url(#pinGrad)"
          />
          <circle cx="20" cy="20" r="9" fill="#06111F" />
          <circle cx="20" cy="20" r="5.5" fill="#c7a14e" opacity="0.9" />
          <defs>
            <linearGradient id="pinGrad" x1="0" y1="0" x2="40" y2="54" gradientUnits="userSpaceOnUse">
              <stop offset="0%" stopColor="#e8d9a0" />
              <stop offset="100%" stopColor="#9e782f" />
            </linearGradient>
          </defs>
        </svg>
      </div>

      <div className="absolute top-4 left-4 z-20 pointer-events-none flex items-center gap-2 bg-[#06111F]/90 border border-[#C9A55C]/15 backdrop-blur-md px-3 py-1.5 rounded-sm">
        <Info className="w-3.5 h-3.5 text-[#C9A55C]" />
        <span className="text-[9px] font-bold text-white uppercase tracking-widest font-sans">
          Store Locator Map Network
        </span>
      </div>

      <div className="absolute bottom-4 left-4 right-4 z-20 pointer-events-auto bg-[#06111F]/85 border border-[#C9A55C]/30 backdrop-blur-lg px-4 py-3 rounded-md flex items-center justify-between gap-2 shadow-2xl transition-all duration-300 hover:border-[#C9A55C] hover:bg-[#06111F]/95">
        <div className="min-w-0">
          <h4 className="text-[11px] font-extrabold text-white uppercase tracking-wider font-sans truncate">
            Hanumangarh Flagship Showroom
          </h4>
          <p className="text-[9.5px] text-gray-400 font-sans mt-0.5 truncate">
            52 Main Bus Stand | Open 10 AM – 8:30 PM
          </p>
        </div>
        <span className="flex-shrink-0 text-[8.5px] font-bold uppercase tracking-widest text-[#C9A55C] border border-[#C9A55C]/40 bg-[#C9A55C]/5 px-2.5 py-1 rounded-sm font-sans whitespace-nowrap">
          Main Showroom
        </span>
      </div>

      <svg className="absolute inset-0 w-full h-full z-30" style={{ pointerEvents: 'none' }}>
        {MAP_NODES.map((node) => {
          if (node.isFlagship) return null;
          return (
            <circle
              key={`hit-${node.id}`}
              cx={node.x}
              cy={node.y}
              r="20"
              fill="transparent"
              style={{ pointerEvents: 'all', cursor: 'pointer' }}
              onMouseEnter={(e) => { e.stopPropagation(); setHoveredNode(node); }}
              onMouseLeave={() => setHoveredNode(null)}
              onClick={(e) => {
                e.stopPropagation();
                window.open(
                  `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(node.name + ', ' + node.details.split('|')[0] + ', Haryana')}`,
                  '_blank'
                );
              }}
            />
          );
        })}
      </svg>

      {hoveredNode && !hoveredNode.isFlagship && (
        <div
          className="absolute bottom-[72px] left-4 right-4 z-40 bg-[#0b131e]/95 border border-[#c7a14e]/30 backdrop-blur-lg p-3 rounded shadow-2xl cursor-pointer"
          style={{ pointerEvents: 'all' }}
          onClick={(e) => {
            e.stopPropagation();
            window.open(
              `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(hoveredNode.name + ', ' + hoveredNode.details.split('|')[0] + ', Haryana')}`,
              '_blank'
            );
          }}
        >
          <div className="flex items-center justify-between mb-1">
            <h4 className="text-[10px] font-bold text-white uppercase tracking-wider font-sans">{hoveredNode.name}</h4>
            <span className="text-[8px] font-bold uppercase px-1.5 py-0.5 rounded tracking-wide border bg-white/5 border-white/10 text-white/70">
              {hoveredNode.role}
            </span>
          </div>
          <p className="text-[9px] text-gray-400 font-sans">{hoveredNode.details}</p>
        </div>
      )}
    </div>
  );
}

